
/* Key handled server-side */
// Logo
var __LT_LOGO = 'data:image/jpeg;base64,';
function __injectLogos(){
  var ids=['__ltLogoNav','__ltLogoFoot','__ltLogoSb1','__ltLogoSb2','__ltLogoSb3','__ltLogoEssay','__ltLogoEssayBar','__ltLogoFeedback','__ltLogoHw'];
  ids.forEach(function(id){var el=document.getElementById(id);if(el)el.src=__LT_LOGO;});
}
document.addEventListener('DOMContentLoaded',__injectLogos);
setTimeout(__injectLogos,200);
/* API calls go to /api/anthropic (Vercel serverless proxy) */

